            byte[](control_id),
            byte[1](byte(0x01)),
            byte[1](byte(0x21))
        ));

        byte[32] seed = sha256(byte[](ticket_root) + byte[](randomness));
        int seed_0 = int(seed[0]);
        int seed_1 = int(seed[1]);
        int seed_2 = int(seed[2]);
        int seed_3 = int(seed[3]);
        int seed_4 = int(seed[4]);
        int seed_5 = int(seed[5]);
        int seed_6 = int(seed[6]);
        if (seed_0 < 0) { seed_0 = seed_0 + 256; }
        if (seed_1 < 0) { seed_1 = seed_1 + 256; }
        if (seed_2 < 0) { seed_2 = seed_2 + 256; }
        if (seed_3 < 0) { seed_3 = seed_3 + 256; }
        if (seed_4 < 0) { seed_4 = seed_4 + 256; }
        if (seed_5 < 0) { seed_5 = seed_5 + 256; }
        if (seed_6 < 0) { seed_6 = seed_6 + 256; }
        int winner_from_seed = (
